// GDPR Art. 17 — right-to-be-forgotten handler. Forwards the request
// to the backend; backend is responsible for scrubbing across all
// sub-processors and returning the audit trail. Exposed at
// POST /api/v1/privacy/erasure.

export default defineEventHandler(async (event) => {
  const config = useRuntimeConfig()
  const backend = config.backendUrl as string
  const body = await readBody(event).catch(() => ({}))

  const upstream = await fetch(`${backend}/api/v1/privacy/erasure`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  })

  setResponseStatus(event, upstream.status)
  setResponseHeader(event, "Content-Type", "application/json")
  return await upstream.text()
})
